 function postProcess(tokens: Token[]): Token[] {
-  return detectArraySubscripts(combineParameterizedTypes(tokens));
+  return detectArraySubscripts(promotePipeClauses(combineParameterizedTypes(tokens)));
 }
+
+// AGGREGATE and EXTEND are pipe-only clauses, so reserve them only when they
+// immediately follow a pipe operator. This keeps their traditional-query use
+// as identifiers unchanged.
+function promotePipeClauses(tokens: Token[]): Token[] {
+  let previous = EOF_TOKEN;
+  return tokens.map(token => {
+    const promoted =
+      previous.type === TokenType.PIPE && (token.text === 'AGGREGATE' || token.text === 'EXTEND')
+        ? { ...token, type: TokenType.RESERVED_CLAUSE, text: token.text.toUpperCase() }
+        : token;
+    if (token.type !== TokenType.LINE_COMMENT && token.type !== TokenType.BLOCK_COMMENT) {
+      previous = promoted;
+    }
+    return promoted;
+  });
+}
